14	const DESCRIPTIONS = [
15	  "Grocery store purchase",
16	  "Monthly subscription",
17	  "Online order",
18	  "Restaurant dinner",
19	  "Gas station",
20	  "Pharmacy",
21	  "Coffee shop",
22	  "Movie tickets",
23	  "Bus pass",
24	  "Electric bill",
25	  "Water bill",
26	  "Book purchase",
